/**
 * Server-only typed API client for the Go API.
 *
 * Built on openapi-fetch paired with the `openapi-typescript` types
 * generated by `make generate-api-types`. Every request goes through
 * a Clerk auth middleware that injects the caller's bearer token, so
 * action files only ever deal with typed inputs / outputs -- auth is
 * a side-effect of using this client, not something each call has to
 * remember to wire.
 *
 * Usage:
 *   import { serverApi } from "@/lib/api/server-client";
 *   const { data, error, response } = await serverApi.GET("/me/files", {
 *     params: { query: { scope: "owned" } },
 *   });
 *
 * In practice you never import this module directly -- you import one
 * of the domain action files under `./actions/`, which already wrap
 * the result tuple with `unwrap`.
 */
import "server-only";

import { auth } from "@clerk/nextjs/server";
import createClient, { type Middleware } from "openapi-fetch";

import type { paths } from "./generated/types";

/**
 * Base URL the typed client hits.
 *
 * The OpenAPI spec declares `servers: - url: /api`, so `baseUrl` must
 * already include the `/api` segment. Resolution order:
 *
 *   1. `API_BASE_URL`            (server-only, e.g. `https://api-dev.askatlas.study/api`)
 *   2. `NEXT_PUBLIC_API_BASE_URL` (shared with any future browser client)
 *   3. `/api`                     (same-origin fallback for local dev via Next rewrite)
 */
function resolveBaseUrl(): string {
  return (
    process.env.API_BASE_URL ?? process.env.NEXT_PUBLIC_API_BASE_URL ?? "/api"
  );
}

/**
 * Injects `Authorization: Bearer <clerk-jwt>` when the caller has an
 * active Clerk session. Unauthenticated requests (public endpoints,
 * cron jobs, build-time fetches) pass through without a header, which
 * lets the Go API return its own 401 instead of failing noisily here.
 */
const clerkAuthMiddleware: Middleware = {
  async onRequest({ request }) {
    const { userId, getToken } = await auth();
    if (!userId) return request;
    const token = await getToken();
    if (token) {
      request.headers.set("Authorization", `Bearer ${token}`);
    }
    return request;
  },
};

/**
 * The typed client every server-side call should use.
 *
 * Declared as `const` (not a factory) so Next.js can hoist it once per
 * worker. openapi-fetch's instances are stateless and thread-safe
 * enough for Node's single-threaded event loop.
 */
export const serverApi = createClient<paths>({ baseUrl: resolveBaseUrl() });
serverApi.use(clerkAuthMiddleware);
